  if (!payload || typeof payload !== 'object') {
    return json(400, { error: 'invalid_json' }, { 'X-Request-Id': reqId });
  }

  const emailRaw = payload.email;
  const password = payload.password;

  if (!validateEmail(emailRaw)) {
    return json(400, { error: 'invalid_email' }, { 'X-Request-Id': reqId });
  }
  if (!validatePassword(password)) {
    return json(400, { error: 'invalid_password' }, { 'X-Request-Id': reqId });
  }

  const email = normalizeEmail(emailRaw);
  const emailKey = `${EMAIL_GSI_PK}${email}`;
  const userId = crypto.randomUUID();
  const createdAt = nowIso();

